import numpy as np
from qiskit.quantum_info import Statevector, Pauli

def bloch(sv):
    return tuple(round(float(np.real(sv.expectation_value(Pauli(p)))), 4) for p in ("X", "Y", "Z"))

states = {
    "A": Statevector.from_label("0"),
    "B": Statevector.from_label("-"),
    "C": Statevector.from_label("1"),
    "D": Statevector.from_label("+"),
}
target = (-1.0, 0.0, 0.0)
evidence = {}
proven = []
for k, sv in states.items():
    b = bloch(sv)
    match = all(abs(a - c) < 1e-6 for a, c in zip(b, target))
    evidence[k] = f"option state has Bloch vector {b}; target arrow is {target} (-X axis) -> match={match}"
    if match:
        proven.append(k)

emit_verdict({
    "answer": proven,
    "evidence": evidence,
    "observed": {"target": list(target)},
})
